class Solution {
    public boolean canChange(String start, String target) {
        int n = start.length();
        boolean[] left = new boolean[n];
        boolean[] right = new boolean[n];
        boolean[] occupied = new boolean[n];

        for (int i = 0; i < n; i++) {
            if (start.charAt(i) == 'L') {
                left[i] = true;
            } else if (start.charAt(i) == 'R') {
                right[i] = true;
            } else {
                occupied[i] = true;
            }
        }

        for (int i = 0; i < n; i++) {
            if (target.charAt(i) == 'L') {
                if (!left[i]) {
                    return false;
                }
            } else if (target.charAt(i) == 'R') {
                if (!right[i]) {
                    return false;
                }
            } else {
                if (!occupied[i]) {
                    return false;
                }
            }
        }
    }

    return true;
}
